          for (int t4=16*t1+1;t4<=min(min(PB_M-1,PB_P-2),16*t1+31);t4++) {
            for (int t5=16*t1;t5<=t4-1;t5++) {
              if (t1%2 == 0) {
                A[t5+2][t4] = C[t5][t5] * A[t5+1][t4] + A[t5+2][t4+1] - 4;;
              }
            }
            for (int t5=t4;t5<=min(PB_P-1,16*t1+31);t5++) {
              lbv=1;
              ubv=min(31,PB_P-1);
#pragma ivdep
#pragma vector always
              for (int t6=lbv;t6<=ubv;t6++) {
                if (t1%2 == 0) {
                  B[t4][t5][t6] = D[t6-1][t4][t5] - 5;;
                }
              }
            }
          }
        }
        if ((t1 == 2*t2) && (t3 == 0)) {
          for (int t4=max(PB_M,16*t1+1);t4<=min(PB_P-2,16*t1+31);t4++) {
            for (int t5=16*t1;t5<=t4-1;t5++) {
              if (t1%2 == 0) {
                A[t5+2][t4] = C[t5][t5] * A[t5+1][t4] + A[t5+2][t4+1] - 4;;
              }
            }
          }
        }
        if ((PB_P <= PB_M) && (t1 == 2*t2) && (t1 <= floord(PB_P-2,16)) && (t1 >= ceild(PB_P-32,16)) && (t3 == 0)) {
          lbv=1;
          ubv=min(31,PB_P-1);
#pragma ivdep
#pragma vector always
          for (int t6=lbv;t6<=ubv;t6++) {
            if (t1%2 == 0) {
              B[(PB_P-1)][(PB_P-1)][t6] = D[t6-1][(PB_P-1)][(PB_P-1)] - 5;;
            }
          }
        }
      }
    }
  }
}

  int t1, t2, t3, t4, t5, t6;
 int lb, ub, lbp, ubp, lb2, ub2;
 register int lbv, ubv;
if (PB_L >= 4) {
  for (int t1=0;t1<=floord(PB_L-2,32);t1++) {
    for (int t2=0;t2<=floord(PB_L,32);t2++) {
      for (int t3=0;t3<=floord(PB_L-1,32);t3++) {
        if ((t2 == 0) && (t3 == 0)) {
          for (int t4=max(2,32*t1);t4<=min(PB_L-2,32*t1+31);t4++) {
            B[t4] = E[t4] * F[t4+1] + B[t4-2] + B[t4-1] * 1;;
            for (int t5=1;t5<=min(31,PB_L);t5++) {
              lbv=1;
              ubv=min(31,PB_L-1);
#pragma ivdep
#pragma vector always
              for (int t6=lbv;t6<=ubv;t6++) {
                A[t5][t4+1][t6-1][t4] = C[t4][t5-1][t6] * C[t5-1][t4][t4] - C[t5][t6][t4] * D[t5-1][t4][0] + 4;;
              }
            }
          }
        }
        if (t2 >= -t3+1) {
          lbp=max(2,32*t1);
          ubp=min(PB_L-2,32*t1+31);
#pragma omp parallel for private(lbv,ubv,t5,t6)
          for (int t4=lbp;t4<=ubp;t4++) {
            for (int t5=max(1,32*t2);t5<=min(PB_L,32*t2+31);t5++) {
              lbv=max(1,32*t3);
              ubv=min(PB_L-1,32*t3+31);
#pragma ivdep
#pragma vector always
              for (int t6=lbv;t6<=ubv;t6++) {
                A[t5][t4+1][t6-1][t4] = C[t4][t5-1][t6] * C[t5-1][t4][t4] - C[t5][t6][t4] * D[t5-1][t4][0] + 4;;
              }
            }
          }
        }
      }
    }
  }
}

  int t1, t2, t3, t4;
 int lb, ub, lbp, ubp, lb2, ub2;
 register int lbv, ubv;
if ((PB_L >= 3) && (PB_N >= 2)) {
  lbp=0;
  ubp=floord(PB_L+2*PB_N-3,32);
#pragma omp parallel for private(lbv,ubv,t2,t3,t4)
  for (int t1=lbp;t1<=ubp;t1++) {
    for (int t2=max(ceild(t1-1,2),ceild(32*t1-PB_N-30,32));t2<=min(min(floord(PB_L+PB_N-2,32),floord(32*t1+PB_L+30,64)),t1);t2++) {
      for (int t3=max(max(max(4,32*t1),32*t2+1),64*t2-PB_L+1);t3<=min(min(min(32*t1+31,64*t2+60),PB_L+2*PB_N-3),32*t2+PB_N+30);t3++) {
        for (int t4=max(max(ceild(t3+2,2),32*t2),t3-PB_N+1);t4<=min(min(floord(t3+PB_L-1,2),32*t2+31),t3-1);t4++) {
          A[(t3-t4)-1][(-t3+2*t4)] = B[(-t3+2*t4)][(t3-t4)-1] * A[(t3-t4)][(-t3+2*t4)-2] * 2;;
        }
      }
    }
  }
}
